 1	import { NetworkMapModel, StorageMapModel, type V1beta1Plan } from '@kubev2v/types';
 2	import { useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
 3	import { CATEGORY_TYPES, taskStatuses } from '@utils/constants';
 4	import { getPlanVirtualMachinesMigrationStatus } from '@utils/crds/plans/selectors';
 5	import { isEmpty } from '@utils/helpers';
 6	
 7	export const canDeleteAndPatchPlanMaps = ({
 8	  name,
 9	  namespace,
10	}: {
11	  name?: string;
12	  namespace?: string;
13	}) => {
14	  const [canDeleteNetworkMap] = useAccessReview({
15	    group: '',
16	    name,
17	    namespace,
18	    resource: NetworkMapModel.plural,
19	    verb: 'delete',
20	  });
21	
22	  const [canPatchNetworkMap] = useAccessReview({
23	    group: '',
24	    name,
25	    namespace,
26	    resource: NetworkMapModel.plural,
27	    verb: 'patch',
28	  });
29	
30	  const [canDeleteStorageMap] = useAccessReview({
31	    group: '',
32	    name,
33	    namespace,
34	    resource: StorageMapModel.plural,
35	    verb: 'delete',
36	  });
37	
38	  const [canPatchStorageMap] = useAccessReview({
39	    group: '',
40	    name,
41	    namespace,
42	    resource: StorageMapModel.plural,
43	    verb: 'patch',
44	  });
45	
46	  return canPatchNetworkMap && canDeleteNetworkMap && canPatchStorageMap && canDeleteStorageMap;
47	};
48	
49	export const hasSomeCompleteRunningVMs = (plan: V1beta1Plan) => {
50	  const planHasNeverStarted = !plan.status?.migration?.started;
51	
52	  const migrationHasSomeCompleteRunningVMs = getPlanVirtualMachinesMigrationStatus(plan)?.filter(
53	    (vm) =>
54	      (vm.completed &&
55	        vm.conditions?.find((condition) => condition.type === CATEGORY_TYPES.SUCCEEDED)) ??
56	      vm.phase !== taskStatuses.completed,
57	  );
58	
59	  return !planHasNeverStarted && !isEmpty(migrationHasSomeCompleteRunningVMs);
60	};

